  let currentLanguage = "en";

  function normaliseLanguage(value) {
    if (LANGUAGES[value]) return value;
    const short = String(value || "").toLowerCase().split("-")[0];
    if (short === "zh") return "zh-Hans";
    return LANGUAGES[short] ? short : "en";
  }

  function readLanguage() {
    try { return normaliseLanguage(root.localStorage?.getItem(STORAGE_KEY) || root.navigator?.language); }
    catch { return "en"; }
  }

  function exact(source, language = currentLanguage) {
    if (language === "en") return source;
    const key = reverseEnglish.get(source);
    if (key) return CATALOGUES[language]?.[key] || source;
    const extra = EXTRA[source];
    return extra ? (extra[EXTRA_LANGUAGE_INDEX[language]] || source) : source;
  }

